function ArtifactCard({ artifact, isExpanded, onToggle }) {
  const [imgLoaded, setImgLoaded] = useState(false);
  const [imgError, setImgError] = useState(false);

  return (
    <div
      style={{
        background: "linear-gradient(160deg, #1a1209 0%, #2c1f0e 100%)",
        border: "1px solid #7a5c2e",
        borderRadius: "16px",
        overflow: "hidden",
        boxShadow: isExpanded
          ? "0 0 32px rgba(200,169,126,0.35)"
          : "0 4px 18px rgba(0,0,0,0.5)",
        transition: "box-shadow 0.3s ease, transform 0.2s ease",
        transform: isExpanded ? "scale(1.01)" : "scale(1)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* Image */}
      <div
        style={{
          position: "relative",
          width: "100%",
          paddingBottom: "62%",
          background: "#0d0a05",
          overflow: "hidden",
        }}
      >
        {!imgLoaded && !imgError && (
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "#a0724a",
              fontSize: "2rem",
              letterSpacing: "0.2em",
            }}
          >
            ⏳
          </div>
        )}
        {!imgError ? (
          <img
            src={artifact.imageUrl}
            alt={artifact.title}
            onLoad={() => setImgLoaded(true)}
            onError={() => setImgError(true)}
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              objectFit: "cover",
              opacity: imgLoaded ? 1 : 0,
              transition: "opacity 0.6s ease",
            }}
          />
        ) : (
          <div
            style={{
              position: "absolute",
              inset: 0,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: "3rem",
            }}
          >
            {artifact.icons[0]}
          </div>
        )}
        {/* Object ID badge */}
        <div
          style={{
            position: "absolute",
            top: "10px",
            right: "10px",
            background: "rgba(0,0,0,0.7)",
            color: "#c8a97e",
            fontSize: "0.65rem",
            padding: "3px 8px",
            borderRadius: "8px",
            fontFamily: "monospace",
          }}
        >
          ID: {artifact.id}
        </div>
        {/* Icons overlay */}
        <div
          style={{
            position: "absolute",
            bottom: "10px",
            left: "10px",
            fontSize: "1.4rem",
            display: "flex",
            gap: "6px",
          }}
        >
          {artifact.icons.map((icon, i) => (
            <span
              key={i}
              title={artifact.classification}
              style={{
                background: "rgba(0,0,0,0.65)",
                borderRadius: "50%",
                padding: "4px 7px",
              }}
            >
              {icon}
            </span>
          ))}
        </div>
      </div>

      {/* Card Body */}
      <div style={{ padding: "18px 20px 20px", flex: 1 }}>
        <ArtifactBadge classification={artifact.classification} />
        <h2
          style={{
            margin: "0 0 6px",
            fontSize: "1.05rem",
            fontWeight: 700,
            color: "#f0ddb0",
            lineHeight: 1.3,
          }}
        >
          {artifact.title}
        </h2>
        <p
          style={{
            margin: "0 0 6px",
            fontSize: "0.75rem",
            color: "#a0724a",
            fontStyle: "italic",
          }}
        >
          {artifact.medium} · {artifact.dimensions}
        </p>
        <p
          style={{
            margin: "0 0 12px",
            fontSize: "0.72rem",
            color: "#7a6040",
          }}
        >
          {artifact.creditLine}
        </p>

        {/* Summary */}
        <p
          style={{
            margin: "0 0 14px",
            fontSize: "0.85rem",
            color: "#d4b880",
            lineHeight: 1.65,
            borderLeft: "3px solid #7a5c2e",
            paddingLeft: "12px",
          }}
        >
          {artifact.summary}
        </p>

        {/* Expandable Key Facts */}
        <button
          onClick={onToggle}
          style={{
            background: "none",
            border: "1px solid #7a5c2e",
            color: "#c8a97e",
            borderRadius: "8px",
            padding: "6px 14px",
            fontSize: "0.78rem",
            cursor: "pointer",
            marginBottom: isExpanded ? "12px" : 0,
            transition: "background 0.2s",
          }}
          onMouseEnter={(e) =>
            (e.currentTarget.style.background = "rgba(122,92,46,0.25)")
          }
          onMouseLeave={(e) => (e.currentTarget.style.background = "none")}
        >
          {isExpanded ? "▲ Hide Key Facts" : "▼ Show Key Facts"}
        </button>

        {isExpanded && (
          <div
            style={{
              background: "rgba(0,0,0,0.3)",
              borderRadius: "10px",
              padding: "12px 14px",
              border: "1px solid #3a2a0e",
            }}
          >
            <p
              style={{
                margin: "0 0 6px",
                fontSize: "0.72rem",
                color: "#7a6040",
                textTransform: "uppercase",
                letterSpacing: "0.08em",
              }}
            >
              📚 Wikipedia: {artifact.wikiArticle}
            </p>
            <KeyFactsList facts={artifact.keyFacts} />
          </div>
        )}

        {/* Met Link */}
        <a
          href={artifact.metUrl}
          target="_blank"
          rel="noopener noreferrer"
          style={{
            display: "inline-block",
            marginTop: "14px",
            fontSize: "0.72rem",
            color: "#a0724a",
            textDecoration: "none",
            borderBottom: "1px dotted #7a5c2e",
          }}
        >
          View at metmuseum.org ↗
        </a>
      </div>
    </div>
  );
}

